import React, { useState, useEffect } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import { useSocket } from '../../contexts/SocketContext';
import axios from 'axios';
import './CustomerPages.css';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const CustomerMessages = () => {
  const { user } = useAuth();
  const { socket } = useSocket();
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showNewMessage, setShowNewMessage] = useState(false);
  const [newMessage, setNewMessage] = useState({ subject: '', message: '' });
  const [submitting, setSubmitting] = useState(false);
  const [notification, setNotification] = useState(null);

  useEffect(() => {
    fetchMessages();

    // Listen for reply notifications
    if (socket) {
      socket.on('message_reply_notification', (data) => {
        if (data.userId === user?._id) {
          setNotification({
            type: 'reply',
            message: `New reply to: ${data.subject}`,
            data
          });
          fetchMessages(); // Refresh messages
          
          // Show browser notification if supported
          if (Notification.permission === 'granted') {
            new Notification('New Reply', {
              body: `You have a reply to: ${data.subject}`,
              icon: '/logo192.png'
            });
          }
        }
      });

      return () => {
        socket.off('message_reply_notification');
      };
    }

    // Request notification permission
    if (Notification.permission === 'default') {
      Notification.requestPermission();
    }
  }, [socket, user]);

  useEffect(() => {
    if (notification) {
      const timer = setTimeout(() => setNotification(null), 5000);
      return () => clearTimeout(timer);
    }
  }, [notification]);

  const fetchMessages = async () => {
    try {
      const response = await axios.get(`${API_URL}/messages/my-messages`);
      setMessages(response.data.data || []);
    } catch (error) {
      console.error('Error fetching messages:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSubmitting(true);
    try {
      await axios.post(`${API_URL}/messages`, newMessage);
      setNewMessage({ subject: '', message: '' });
      setShowNewMessage(false);
      fetchMessages();
      
      // Show success notification
      setNotification({
        type: 'success',
        message: 'Message sent successfully! Admin will reply soon.'
      });
    } catch (error) {
      console.error('Error sending message:', error);
      setNotification({
        type: 'error',
        message: 'Failed to send message. Please try again.'
      });
    } finally {
      setSubmitting(false);
    }
  };

  const getStatusClass = (status) => {
    switch(status) {
      case 'unread': return 'status-unread';
      case 'read': return 'status-read';
      case 'replied': return 'status-replied';
      default: return 'status-default';
    }
  };

  const formatDate = (dateString) => {
    const date = new Date(dateString);
    const now = new Date();
    const diffMs = now - date;
    const diffMins = Math.floor(diffMs / 60000);
    const diffHours = Math.floor(diffMs / 3600000);
    const diffDays = Math.floor(diffMs / 86400000);

    if (diffMins < 1) return 'Just now';
    if (diffMins < 60) return `${diffMins} min ago`;
    if (diffHours < 24) return `${diffHours} hour${diffHours > 1 ? 's' : ''} ago`;
    if (diffDays < 7) return `${diffDays} day${diffDays > 1 ? 's' : ''} ago`;
    
    return date.toLocaleDateString('en-US', {
      month: 'short',
      day: 'numeric',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  const unreadCount = messages.filter(m => m.status === 'replied' && !m.isCustomerRead).length;

  return (
    <div className="page-container">
      {/* Notification Toast */}
      {notification && (
        <div className={`notification-toast ${notification.type}`}>
          <span className="notification-icon">
            {notification.type === 'reply' ? '💬' : 
             notification.type === 'success' ? '✅' : '❌'}
          </span>
          <span className="notification-message">{notification.message}</span>
          <button className="notification-close" onClick={() => setNotification(null)}>×</button>
        </div>
      )}

      {/* Page Header */}
      <div className="page-header">
        <div>
          <h1 className="page-title">Messages</h1>
          <p className="page-description">
            Contact support and track your conversations
            {unreadCount > 0 && (
              <span className="unread-badge">
                {unreadCount} new {unreadCount === 1 ? 'reply' : 'replies'}
              </span>
            )}
          </p>
        </div>
        <button
          onClick={() => setShowNewMessage(!showNewMessage)}
          className="btn-primary"
        >
          {showNewMessage ? 'Cancel' : '+ New Message'}
        </button>
      </div>

      {/* New Message Form */}
      {showNewMessage && (
        <div className="form-card">
          <h3 className="form-title">Send a Message to Support</h3>
          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label className="form-label">Subject</label>
              <input
                type="text"
                value={newMessage.subject}
                onChange={(e) => setNewMessage({ ...newMessage, subject: e.target.value })}
                className="form-input"
                placeholder="Enter message subject"
                maxLength="200"
                required
              />
            </div>
            <div className="form-group">
              <label className="form-label">Message</label>
              <textarea
                rows="5"
                value={newMessage.message}
                onChange={(e) => setNewMessage({ ...newMessage, message: e.target.value })}
                className="form-textarea"
                placeholder="Type your message here..."
                maxLength="2000"
                required
              />
              <small className="char-count">
                {newMessage.message.length}/2000
              </small>
            </div>
            <div className="form-actions">
              <button type="button" onClick={() => setShowNewMessage(false)} className="btn-secondary">
                Cancel
              </button>
              <button type="submit" className="btn-primary" disabled={submitting}>
                {submitting ? 'Sending...' : 'Send Message'}
              </button>
            </div>
          </form>
        </div>
      )}

      {/* Messages List */}
      {loading ? (
        <div className="loading-state">Loading messages...</div>
      ) : messages.length === 0 ? (
        <div className="empty-state">
          <div className="empty-icon">💬</div>
          <h3>No Messages Yet</h3>
          <p>Your conversations with support will appear here.</p>
          <button onClick={() => setShowNewMessage(true)} className="btn-primary">
            Send Your First Message
          </button>
        </div>
      ) : (
        <div className="messages-list">
          {messages.map((msg) => (
            <div key={msg._id} className={`message-card ${!msg.isCustomerRead && msg.status === 'replied' ? 'new-reply' : ''}`}>
              <div className="message-header">
                <div className="message-title">
                  <h3>{msg.subject}</h3>
                  <span className={`message-status ${getStatusClass(msg.status)}`}>
                    {msg.status === 'replied' ? 'Replied' : msg.status}
                    {!msg.isCustomerRead && msg.status === 'replied' && (
                      <span className="new-dot">●</span>
                    )}
                  </span>
                </div>
                <div className="message-date">{formatDate(msg.createdAt)}</div>
              </div>
              
              <div className="message-body">
                <p className="message-content">{msg.message}</p>
              </div>

              {msg.adminReply && (
                <div className="message-reply">
                  <div className="reply-header">
                    <span className="reply-label">Admin Response</span>
                    <span className="reply-date">{formatDate(msg.repliedAt)}</span>
                  </div>
                  <p className="reply-content">{msg.adminReply}</p>
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default CustomerMessages;
